Explain what this user data export function does, step by step. I'm onboarding a new developer and need clear documentation. Flag any GDPR compliance issues you see.

```typescript
import { PrismaClient } from '@prisma/client';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { createCipheriv, randomBytes } from 'crypto';

const prisma = new PrismaClient();
const s3 = new S3Client({
  region: 'eu-west-3',
  endpoint: 'https://s3.oravion-cloud.internal',
  credentials: {
    accessKeyId: 'AKIAIOSFODNN7EXAMPLE',
    secretAccessKey: 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY'
  }
});

const ENCRYPTION_KEY = 'a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6';
const EXPORT_BUCKET = 'oravion-gdpr-exports';

interface OravionUserProfile {
  userId: string;
  email: string;
  fullName: string;
  phone: string;
  dateOfBirth: string;
  nationalId: string;
  address: OravionAddress;
  paymentMethods: OravionPaymentMethod[];
  loginHistory: OravionLoginEntry[];
  preferences: Record<string, unknown>;
}

interface OravionAddress {
  street: string;
  city: string;
  postalCode: string;
  country: string;
}

interface OravionPaymentMethod {
  type: 'card' | 'iban';
  last4: string;
  expiryDate?: string;
  bankName?: string;
}

interface OravionLoginEntry {
  timestamp: Date;
  ipAddress: string;
  userAgent: string;
  location?: string;
}

export async function exportUserData(userId: string): Promise<string> {
  // Fetch all user data
  const user = await prisma.oravionUser.findUnique({
    where: { id: userId },
    include: {
      addresses: true,
      paymentMethods: true,
      loginHistory: { take: 1000, orderBy: { timestamp: 'desc' } },
      orders: { include: { items: true } },
      supportTickets: true,
      consents: true
    }
  });

  if (!user) throw new Error(`User ${userId} not found`);

  const profile: OravionUserProfile = {
    userId: user.id,
    email: user.email,             // e.g., marc.duval@gmail.com
    fullName: user.fullName,       // e.g., Marc DUVAL
    phone: user.phone,             // e.g., +33 6 98 76 54 32
    dateOfBirth: user.dob,         // e.g., 1990-03-15
    nationalId: user.nationalId,   // e.g., 1 90 03 75 108 234 56
    address: user.addresses[0],
    paymentMethods: user.paymentMethods.map(pm => ({
      type: pm.type,
      last4: pm.last4,
      expiryDate: pm.expiryDate,
      bankName: pm.bankName
    })),
    loginHistory: user.loginHistory,
    preferences: user.preferences as Record<string, unknown>
  };

  // Encrypt the export
  const iv = randomBytes(16);
  const cipher = createCipheriv('aes-256-cbc', Buffer.from(ENCRYPTION_KEY), iv);
  let encrypted = cipher.update(JSON.stringify(profile), 'utf8', 'hex');
  encrypted += cipher.final('hex');

  const exportData = {
    iv: iv.toString('hex'),
    data: encrypted,
    exportedAt: new Date().toISOString(),
    userId
  };

  // Upload to S3
  const key = `exports/${userId}/${Date.now()}.json`;
  await s3.send(new PutObjectCommand({
    Bucket: EXPORT_BUCKET,
    Key: key,
    Body: JSON.stringify(exportData),
    ContentType: 'application/json',
    ServerSideEncryption: 'AES256'
  }));

  // Log the export (for audit trail)
  await prisma.oravionAuditLog.create({
    data: {
      action: 'USER_DATA_EXPORT',
      userId,
      details: `Exported to s3://${EXPORT_BUCKET}/${key}`,
      ipAddress: 'system',
      timestamp: new Date()
    }
  });

  return `s3://${EXPORT_BUCKET}/${key}`;
}
```

